#include <bits/stdc++.h>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18;int dx[4] = {-1, 1, -1, 1}, dy[4] = {-1, -1, 1, 1};  // --- LOGIC ---void solve() {    long long a, b; 		cin >> a >> b;		long long x_king, y_king; 		cin >> x_king >> y_king;		long long x_queen, y_queen; 		cin >> x_queen >> y_queen;		set<pair<int, int>> king_hits, queen_hits;		for (int j = 0; j < 4; j++)		{			king_hits.insert({x_king + dx[j] * a, y_king + dy[j] * b});			king_hits.insert({x_king + dx[j] * b, y_king + dy[j] * a});			queen_hits.insert({x_queen + dx[j] * a, y_queen + dy[j] * b});			queen_hits.insert({x_queen + dx[j] * b, y_queen + dy[j] * a});		}		int ans = 0; 		for (auto position : king_hits)			if (queen_hits.find(position) != queen_hits.end())				ans++; 		cout << ans << endl;     } // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}